import (
	"sort"
)

func solve(nums []int64, k int64) int64 {
	sort.Ints(nums)
	n := len(nums)
	maxWindow := 0
	for i := 0; i < n; i++ {
		target := nums[i] * k
		low, high := i, n-1
		bestJ := i - 1
		for low <= high {
			mid := (low + high) / 2
			if nums[mid] <= target {
				bestJ = mid
				low = mid + 1
			} else {
				high = mid - 1
			}
		}
		currentWindow := bestJ - i + 1
		if currentWindow > maxWindow {
			maxWindow = currentWindow
		}
	}
	return int64(n - maxWindow)
}
